@WebServlet("/login")
// Definition of LoginServlet class
public class LoginServlet extends HttpServlet {
    @Override
    protected void doPost(HttpServletRequest req,
                          HttpServletResponse resp)
            throws ServletException, IOException {

        // Variable declaration and initialization
        String user = req.getParameter("username");
        String pass = req.getParameter("password");

        // Conditional branching
        if (authenticate(user, pass)) {
            // Get session (create new if none exists)
            HttpSession session = req.getSession();
            session.setAttribute("loginUser", user);
            session.setMaxInactiveInterval(1800); // 30 minutes
            resp.sendRedirect("/app/mypage");
        } else {
            resp.sendRedirect("/app/login?error=true");
        }
    }
}
@WebServlet("/mypage")
// Definition of MyPageServlet class
public class MyPageServlet extends HttpServlet {
    @Override
    protected void doGet(HttpServletRequest req,
                         HttpServletResponse resp)
            throws ServletException, IOException {

        HttpSession session = req.getSession(false); // Existing session only
        if (session == null || session.getAttribute("loginUser") == null) {
            resp.sendRedirect("/app/login"); // Not logged in → redirect
            return;
        }

        String user = (String) session.getAttribute("loginUser");
        resp.setContentType("text/html; charset=UTF-8");
        resp.getWriter().println("<h1>Welcome, " + user + "</h1>");
    }
}

