public class UserListServlet extends HttpServlet {
    @Override
    protected void doGet(HttpServletRequest req,
                         HttpServletResponse resp)
            throws ServletException, IOException {

        // Model: Retrieve data
        List<String> users = List.of("Taro Yamada", "Hanako Sato", "Ichiro Suzuki");

        // Set Model data in Request scope
        req.setAttribute("users", users);
        req.setAttribute("title", "User List");

        // Forward to View (JSP)
        RequestDispatcher rd =
            req.getRequestDispatcher("/WEB-INF/views/userList.jsp");
        rd.forward(req, resp);
    }
}
// Forward: Delegates processing to JSP internally on the server (URL does not change)
