import jakarta.servlet.*;
import jakarta.servlet.annotation.WebFilter;
import jakarta.servlet.http.*;
import java.io.IOException;

// Filter applied to all requests
@WebFilter("/*")
// Definition of EncodingFilter class
public class EncodingFilter implements Filter {

    @Override
    public void doFilter(ServletRequest req, ServletResponse resp,
                         FilterChain chain)
            throws IOException, ServletException {

        // Pre-processing: Set character encoding
        req.setCharacterEncoding("UTF-8");
        resp.setCharacterEncoding("UTF-8");

        // Measure processing time (for logging)
        // Variable declaration and initialization
        long start = System.currentTimeMillis();

        // Delegate processing to the next filter or servlet
        chain.doFilter(req, resp);

        // Post-processing: Log processing time
        long elapsed = System.currentTimeMillis() - start;
        System.out.printf("[%s] %s (%dms)%n",
            ((HttpServletRequest) req).getMethod(),
            ((HttpServletRequest) req).getRequestURI(),
            elapsed);
    }
}

@WebFilter("/app/*")  // Applied to paths under /app/
// Definition of AuthFilter class
public class AuthFilter implements Filter {

    // Paths that don't require the filter
    private static final Set<String> EXCLUDED = Set.of(
        "/app/login", "/app/register", "/app/public"
    );

    @Override
    public void doFilter(ServletRequest req, ServletResponse resp,
                         FilterChain chain)
            throws IOException, ServletException {

        HttpServletRequest httpReq = (HttpServletRequest) req;
        HttpServletResponse httpResp = (HttpServletResponse) resp;

        // Variable declaration and initialization
        String path = httpReq.getRequestURI();

        // Skip excluded paths
        // Conditional branching
        if (EXCLUDED.contains(path)) {
            chain.doFilter(req, resp);
            return;
        }

        // Session check
        HttpSession session = httpReq.getSession(false);
        if (session != null && session.getAttribute("loginUser") != null) {
            chain.doFilter(req, resp); // Logged in → pass through
        } else {
            httpResp.sendRedirect("/app/login"); // Not logged in → login page
        }
    }
}

